instance MessageDecode TaskQueueConfig where
  messageDecoder = loop Nothing Nothing Map.empty
    where
      loop acc_0 acc_1 acc_2 = do
        mTag <- getTagOr
        case mTag of
          Nothing -> pure (TaskQueueConfig {taskQueueConfigQueueratelimit = acc_0, taskQueueConfigFairnesskeysratelimitdefault = acc_1, taskQueueConfigFairnessweightoverrides = acc_2})
          Just (Tag fn wt) -> case fn of
            1 -> do
              v <- decodeFieldMessage
              loop (Just v) acc_1 acc_2
            2 -> do
              v <- decodeFieldMessage
              loop acc_0 (Just v) acc_2
            3 -> do
              bs' <- getLengthDelimited
              let decodeEntry = runDecoder (decodeMapEntry decodeFieldString decodeFieldFloat "" 0) bs'
              case decodeEntry of
                Left _ -> loop acc_0 acc_1 acc_2
                Right (mk', mv') -> loop acc_0 acc_1 (Map.union acc_2 (Map.singleton mk' mv'))
            _ -> skipField wt >> loop acc_0 acc_1 acc_2

instance ProtoToJSON TaskQueueConfig where
  protoToJSON msg = jsonObject
      [ "queueRateLimit" .= msg.taskQueueConfigQueueratelimit
      , "fairnessKeysRateLimitDefault" .= msg.taskQueueConfigFairnesskeysratelimitdefault
      , "fairnessWeightOverrides" .= msg.taskQueueConfigFairnessweightoverrides
      ]

instance ProtoFromJSON TaskQueueConfig where
  protoFromJSON _ = Right defaultTaskQueueConfig